/* === FreeRTOS 通信机制选型决策树（伪代码）=== */

typedef enum {
    COMM_DATA_STREAM,   /* 数据流：传感器→控制器 */
    COMM_SYNC_EVENT,    /* 同步事件：SPI 完成→主任务 */
    COMM_MULTI_WAIT,    /* 多条件等待：DMA+SPI 都完成→渲染 */
    COMM_RESOURCE_POOL  /* 资源池：4 个 DMA 通道 */
} comm_pattern_t;

/* 根据通信模式返回推荐的 FreeRTOS 原语 */
comm_handle_t select_comm_primitive(comm_pattern_t pattern) {
    switch (pattern) {
    case COMM_DATA_STREAM:
        /* 如果需要最新值覆盖旧值：单槽队列 + Overwrite */
        return xQueueCreate(1, sizeof(sensor_data_t));
        /* 如果需要完整历史：深度 N 队列 */
        // return xQueueCreate(64, sizeof(sensor_data_t));

    case COMM_SYNC_EVENT:
        /* 二值信号量：最小开销的「事件通知」 */
        return xSemaphoreCreateBinary();

    case COMM_MULTI_WAIT:
        /* 事件组：支持 AND/OR 组合等待 */
        return xEventGroupCreate();

    case COMM_RESOURCE_POOL:
        /* 计数信号量：初始值 = 可用资源数 */
        return xSemaphoreCreateCounting(4, 4);
    }
    return NULL;
}

/* === 传感器数据：单槽队列 + Overwrite 模式 === */
#include "FreeRTOS.h"
#include "queue.h"
#include "task.h"

#define SENSOR_QUEUE_DEPTH    1
#define SENSOR_SAMPLE_RATE_HZ 1000
#define CONTROL_PERIOD_US     100  /* 10kHz PID 控制频率 */

typedef struct {
    float accel_x;   /* m/s² */
    float accel_y;   /* m/s² */
    float accel_z;   /* m/s² */
    uint32_t timestamp_us; /* 微秒级时间戳 */
} sensor_reading_t;

static QueueHandle_t sensor_queue;
static TaskHandle_t  control_task_handle;

/* 初始化：必须在某个任务上下文中调用一次 */
void sensor_comm_init(void) {
    sensor_queue = xQueueCreate(SENSOR_QUEUE_DEPTH, sizeof(sensor_reading_t));
    configASSERT(sensor_queue);  /* 堆不足时这里会断言 */
}

/* ISR 回调：ADC 转换完成时由 HAL 调用（假设采样率 1kHz）*/
void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *hadc) {
    static sensor_reading_t reading;
    BaseType_t xHigherPriorityTaskWoken = pdFALSE;

    /* 读取 ADC 值并转换为物理量 */
    reading.accel_x = (float)HAL_ADC_GetValue(hadc) * 0.001f - 9.81f;
    reading.accel_y = (float)HAL_ADC_GetValue(hadc) * 0.001f - 9.81f;
    reading.accel_z = (float)HAL_ADC_GetValue(hadc) * 0.001f - 9.81f;
    reading.timestamp_us = (uint32_t)xTaskGetTickCount() * portTICK_PERIOD_MS * 1000;

    /* 写入单槽队列 —— 覆盖旧值，不阻塞 ISR */
    xQueueOverwriteFromISR(sensor_queue, &reading, &xHigherPriorityTaskWoken);

    /* 如果唤醒了一个更高优先级的任务，立即切换 */
    portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
}

/* 控制任务：以 10kHz 频率从队列读取最新传感器数据 */
void ControlTask(void *pvParameters) {
    sensor_reading_t latest;
    for (;;) {
        /* Peek 最新值，不删除 —— PID 可能需要多次读取 */
        if (xQueuePeek(sensor_queue, &latest, pdMS_TO_TICKS(CONTROL_PERIOD_US))) {
            /* 使用 latest.accel_x/y/z 执行 PID 计算 */
            float error = latest.accel_z - SETPOINT_Z;
