}

/* === 陷阱演示：优先级翻转的复现与修复 === */

/* ❌ 错误做法：用普通二进制信号量（无优先级继承）*/
SemaphoreHandle_t shared_sem = xSemaphoreCreateBinary();

void LowPriorityTask(void *pv) {
    for (;;) {
        xSemaphoreTake(shared_sem, portMAX_DELAY);
        /* 持有锁 5ms —— 高优先级任务在等这个锁！*/
        HAL_Delay(5);
        xSemaphoreGive(shared_sem);
    }
}

/* ✅ 正确做法：用互斥量（自动优先级继承）*/
SemaphoreHandle_t shared_mutex = xSemaphoreCreateMutex();

void HighPriorityTask(void *pv) {
    for (;;) {
        /* 如果 Mutex 被低优先级任务持有，
           低优先级任务会自动提升到本任务优先级 */
        xSemaphoreTake(shared_mutex, portMAX_DELAY);
        /* 临界区 —— 执行时间短，减少优先级提升的持续时间 */
        process_critical_data();
        xSemaphoreGive(shared_mutex);
        /* 恢复原始优先级 */
    }
}

/* === 重构前：全局变量共享（竞态条件 + 关中断保护）=== */
static volatile float adc_value;       /* 全局共享变量 */
static volatile float gyro_value;      /* 第二个传感器也需要全局变量 */

/* ADC 中断任务 —— 写入 adc_value */
void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *hadc) {
    adc_value = (float)HAL_ADC_GetValue(hadc) * 0.001f;
    /* 没有同步机制！PID 任务可能在写入中途读取 */
}

/* PID 控制任务 —— 读取 adc_value */
void PID_Task(void *pvParameters) {
    for (;;) {
        __disable_irq();           /* 关中断保护读操作 */
        float value = adc_value;   /* 原子读取 */
        __enable_irq();

        float error = SETPOINT - value;
        float output = Kp * error;  /* 简化 PID */
        TIM2->CCR1 = (uint32_t)(output * TIM2->ARR);

        vTaskDelay(pdMS_TO_TICKS(100));
    }
}

/* === 重构后：队列通信（零竞态条件，无需关中断）=== */

/* 第一步：定义消息结构 */
typedef struct {
    float adc_raw;
    float gyro_raw;
    uint32_t tick_count;
} sensor_msg_t;

/* 第二步：创建单槽队列（在某个初始化函数中）*/
static QueueHandle_t sensor_msg_queue;

void sensor_comm_init(void) {
    sensor_msg_queue = xQueueCreate(1, sizeof(sensor_msg_t));
    configASSERT(sensor_msg_queue);
}

/* 第三步：ADC 中断 —— 发送消息副本 */
void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *hadc) {
    static sensor_msg_t msg;
    BaseType_t xWoken = pdFALSE;

    msg.adc_raw   = (float)HAL_ADC_GetValue(hadc) * 0.001f;
    msg.gyro_raw  = (float)HAL_ADC_GetValue(&hadc2) * 0.001f;
    msg.tick_count = xTaskGetTickCount();

    /* 覆盖写入 —— 保证控制任务永远拿到最新数据 */
    xQueueOverwriteFromISR(sensor_msg_queue, &msg, &xWoken);
    portYIELD_FROM_ISR(xWoken);
}

/* 第四步：PID 控制任务 —— 接收消息 */
void PID_Task(void *pvParameters) {
    sensor_msg_t msg;
    for (;;) {
        /* 阻塞等待新数据，超时 10ms */
        if (xQueueReceive(sensor_msg_queue, &msg, pdMS_TO_TICKS(10))) {
            float error = SETPOINT - msg.adc_raw;
            float output = Kp * error;
            TIM2->CCR1 = (uint32_t)(output * TIM2->ARR);
            /* 不需要关中断！队列内部已处理同步 */
        }
    }
}
